# Load data
docs_file = locals()['var_functions.query_db:12']
funding_file = locals()['var_functions.query_db:14']

with open(docs_file, 'r') as f:
    documents = json.load(f)

with open(funding_file, 'r') as f:
    funding = json.load(f)

# Extract disaster projects from documents
disaster_projects = set()

for doc in documents:
    text = doc['text']
    filename = doc['filename']

    lines = text.split('\n')
    for line in lines:
        line = line.strip()
        if '(FEMA Project)' in line or '(CalOES Project)' in line or '(CalJPIA Project)' in line:
            if '2022' in text or '2022' in filename:
                clean_name = line.replace('•', '').replace('·', '').strip()
                if clean_name:
                    disaster_projects.add(clean_name)

# Calculate total funding
total_funding = 0
for proj in disaster_projects:
    for record in funding:
        if record['Project_Name'] == proj:
            total_funding += int(record['Amount'])

result = {'total_funding': total_funding}
print('__RESULT__:')
print(json.dumps(result))"}}

